      return response["usage"] if response["usage"]
      return response["usageMetadata"] if response["usageMetadata"]

      usage = {}
      %w[prompt_eval_count eval_count].each do |key|
        usage[key] = response[key] if response.key?(key)
      end
      usage.empty? ? nil : usage
    end
  end
